def fibonacci(n):
    """Iterative fibonacci with O(n) time and O(1) space."""
    if n == 0:
        return 0
    a, b = 0, 1
    for _ in range(n - 1):
        a, b = b, a + b
    return b

def fibonacci(n):
    """Compute F(n) using fast doubling.

    Uses the identities:
        F(2k)   = F(k) * [2*F(k+1) - F(k)]
        F(2k+1) = F(k)^2 + F(k+1)^2
    """
    if n < 0:
        raise ValueError("n must be >= 0")
    if n <= 1:
        return n

    def fast_double(k):
        if k == 0:
            return (0, 1)
        fk, fk1 = fast_double(k >> 1)
        even = fk * (2 * fk1 - fk)
        odd = fk * fk + fk1 * fk1
        if k & 1:
            return (odd, even + odd)
        return (even, odd)

    return fast_double(n)[0]

def fibonacci(n):
    if n < 0:
        raise ValueError("n cannot be negative")
    if n == 0:
        return 0
    if n <= 2:
        return 1

    # Matrix exponentiation: [[1,1],[1,0]]^n gives F(n)
    def mat_mul(a, b):
        return [
            [a[0][0]*b[0][0] + a[0][1]*b[1][0], a[0][0]*b[0][1] + a[0][1]*b[1][1]],
            [a[1][0]*b[0][0] + a[1][1]*b[1][0], a[1][0]*b[0][1] + a[1][1]*b[1][1]]
        ]

    def mat_pow(mat, exp):
        res = [[1, 0], [0, 1]]
        while exp:
            if exp & 1:
                res = mat_mul(res, mat)
            mat = mat_mul(mat, mat)
            exp >>= 1
        return res

    m = mat_pow([[1, 1], [1, 0]], n)
    return m[0][1]

def fibonacci(n):
    """Bottom-up DP with memoization table."""
    if n <= 0:
        return 0
    if n == 1:
        return 1

    dp = {0: 0, 1: 1}
    for i in range(2, n + 1):
        dp[i] = dp[i-1] + dp[i-2]
    return dp[n]

def fibonacci(n):
    _memo = {0: 0, 1: 1}

    def _fib(k):
        if k in _memo:
            return _memo[k]
        if k % 2 == 0:
            half = k // 2
            f_half = _fib(half)
            f_half_minus = _fib(half - 1)
            val = f_half * (2 * f_half_minus + f_half)
        else:
            half = (k - 1) // 2
            f_half = _fib(half)
            f_half_plus = _fib(half + 1)
            val = f_half * f_half + f_half_plus * f_half_plus
        _memo[k] = val
        return val

    return _fib(n)

def fibonacci(n):
    if n < 0:
        raise ValueError("n must be non-negative")
    if n == 0:
        return 0
    if n == 1:
        return 1
    previous = 0
    current = 1
    for _ in range(2, n + 1):
        previous, current = current, previous + current
    return current
